/**
 * =============================
 * ACCORDION FUNCTIONALITY
 * =============================
 */

function initAccordion() {
	const acc = document.getElementsByClassName("accordion-slide");

	if (!acc || acc.length === 0) {
		return;
	}

	const toggleAccordion = (e) => {
		let target = e.currentTarget;
		if (!target.classList.contains("active")) {
			Array.from(acc).forEach((slide) => {
				slide.classList.remove("active");
				slide.children[1].style.display = "none";
			});
			target.classList.add("active");
			target.children[1].style.display = "block";
		} else {
			target.classList.remove("active");
			target.children[1].style.display = "none";
		}
	};

	Array.from(acc).forEach((slide) => {
		slide.addEventListener("click", (e) => toggleAccordion(e));
	});
}

/**
 * =============================
 * REVIEWS EXPAND/COLLAPSE
 * =============================
 */

function initReviewsExpand() {
	const buttons = document.querySelectorAll('.quote-attribution');

	buttons.forEach(button => {
		button.addEventListener('click', function() {
			let dots = this.parentNode.querySelector('#dots');
			let moreText = this.parentNode.querySelector('#more');

			if (dots && moreText) {
				if (dots.style.display === "none") {
					dots.style.display = "inline";
					this.innerHTML = "Read more";
					moreText.style.display = "none";
				} else {
					dots.style.display = "none";
					this.innerHTML = "Read less";
					moreText.style.display = "inline";
				}
			}
		});
	});
}

/**
 * =============================
 * INITIALIZATION
 * =============================
 */

// Initialize quiz immediately
initQuiz();

// Initialize when DOM is ready
if (document.readyState === 'loading') {
	document.addEventListener('DOMContentLoaded', () => {
		initMarqueeParallax();
		initCarousels();
		initAccordion();
		initReviewsExpand();
	});
} else {
	initMarqueeParallax();
	initCarousels();
	initAccordion();
	initReviewsExpand();
}

