/**
 * Womens Hormone Imbalance Hero Variant
 * Page-specific styles for the enhanced PDP hero section only.
 * All other section styles are loaded via the base womens-hormone-imbalance.css.
 *
 * Desktop-first: base styles target desktop (1440px).
 * Tablet/mobile overrides via $medium-screen-and-smaller (max-width: 1024px).
 * Mobile-only refinements via $small-screen-only (max-width: 600px).
 */
@use '../variables/colors' as colors;
@use '../variables/fonts' as fonts;
@use '../variables/layout' as layout;

.womens-hormone-imbalance-hero {

	/*
	* =============================
	* Hero
	* =============================
	*/
	.hone-your-hormones.hero {
		background-color: colors.$color-white;
		padding: fonts.rem(40px) fonts.rem(64px);
		@media #{layout.$medium-screen-and-smaller} {
			padding: fonts.rem(16px) fonts.rem(32px) fonts.rem(40px);
			flex-direction: column;
			gap: fonts.rem(24px);
		}
		@media #{layout.$small-screen-only} {
			padding-inline: fonts.rem(16px);
		}

		.container.grid {
			max-width: 1440px;
			margin: 0 auto;
			gap: fonts.rem(64px);
			grid-template-columns: 600px 1fr;
			@media #{layout.$medium-screen-and-smaller} {
				grid-template-columns: 1fr;
				gap: 0;
				padding-inline: 0;
			}
		}

		.container {
			@media #{layout.$medium-screen-and-smaller} {
				display: flex;
				flex-direction: column;
				gap: 0;
			}
		}

		// Left column — video/gif
		.media-wrapper {
			padding: 0;
			display: flex;
			align-items: center;
			background-color: colors.$color-white;
			@media #{layout.$medium-screen-and-smaller} {
				order: 1;
			}

			.media-block {
				width: 600px;
				aspect-ratio: 1 / 1;
				@media #{layout.$medium-screen-and-smaller} {
					width: 100%;
					max-width: fonts.rem(600px);
					height: auto;
					margin-left: auto;
					margin-right: auto;
				}

				video {
					width: 100%;
					height: 100%;
					object-fit: cover;
				}
			}
		}

