/**
 * Adapted Legacy Template
 * Womens Hormone Imbalance
 *
 * Add basic overrides at top of file ("BASIC OVERRIDES")
 * Basic overrides can then be overridden by the legacy styles as necessary
 * Add additional custom styles at bottom of file ("CUSTOM STYLES")
 */
@use '../variables/layout' as layout;
@use '../variables/colors' as colors;
@use '../variables/fonts' as fonts;

@use '../legacy/styles/womens-hormone-imbalance' as legacy-styles;
@use '../legacy/styles/monitor-indicators-paralax' as monitor-parallax;

/**
* =============================
* BASIC OVERRIDES
* =============================
*/
.cta-block a {
	border-radius: 0;
	border: none;
	letter-spacing: 0.05rem;
	padding-inline: 2rem;
	&:hover {
		background: #f8f93f;
	}
}

/**
* =============================
* ORIGINAL STYLES
* =============================
*/	
@include legacy-styles.legacy-styles();
@include monitor-parallax.monitor-indicators-parallax();

/**
* =============================
* CUSTOM STYLES
* =============================
*/
/* Fix for slick carousel slides being hidden by global [aria-hidden="true"] rule in _reset.scss */
.slick-slider .slick-slide[aria-hidden="true"] {
	display: block !important;
}

