/*
 * =============================
 * How Healthy Am I
 * =============================
 */
.how-healthy-am-i {
	border-bottom: 1px solid colors.$color-black-lightest;

	@media #{layout.$small-screen-only} {
		border-bottom: 0;
	}

	.container {
		padding: 4rem;	
		max-width: 1920px;
		@media #{layout.$medium-screen-and-smaller} {
			padding: 2.5rem;
		}
		@media #{layout.$small-screen-only} {
			padding-inline: 1rem;
		}

		.wrapper {
			padding: 0;
		}

		.content-wrapper {
			text-align: center;
			margin-bottom: 2.5rem;
			@media #{layout.$small-screen-only} {
				margin-bottom: 1.5rem;
			}
			h2 {
				font-family: "STIX Two Text", serif;
				font-size: 3.625rem;
				font-weight: 400;
				line-height: 100%;
				letter-spacing: -1.16px;
				margin-bottom: 1rem;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: 2.25rem;
					letter-spacing: -0.72px;
				}
			}
			p {
				font-family: "DM Sans", sans-serif;
				font-size: 1.375rem;
				font-weight: 500;
				line-height: 1;
				letter-spacing: -0.44px;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: 1.125rem;
					letter-spacing: -0.36px;
				}
			}
		}

		.buttons-wrapper {
			display: grid;
			grid-template-columns: repeat(8, auto);
			gap: 1rem;
			margin-bottom: 2rem;
			justify-content: center;

			@media only screen and (max-width: 1380px) {
				grid-template-columns: repeat(4, 1fr);
			}
