function trackQuizEvent(action, label) {
    const slug = window.location.pathname;
    window.dataLayer.push({
        event: "gaEventTrigger",
        gaEventCategory: 'Quiz',
        gaEventOrigin: slug,
        gaEventAction: action,
        gaEventLabel: label
    });
}

// Make function available globally (for non-bundled usage)
window.trackQuizEvent = trackQuizEvent;

// ES module export (for bundled usage)
export { trackQuizEvent };

